dslRule:
/*!id: logical.simplification.boolean-if-else.true-false*/
/*!description: Simplify 'if (condition) return true; else return false;' to 'return condition;'>*/
/*!severity: info*/
if ($condition$) {
    return true;
} else {
    return false;
}
=> return $condition$;
;;

/*!id: logical.simplification.boolean-if-else.false-true*/
/*!description: Simplify 'if (condition) return false; else return true;' to 'return !condition;'>*/
/*!severity: info*/
if ($condition$) {
    return false;
} else {
    return true;
}
=> return !$condition$;
;;

/*!id: jdt.internal.javaplugin.getjavacorepluginpreferences.to.new*/
/*!description: Replace deprecated JavaPlugin.getJavaCorePluginPreferences() with JavaPlugin.getJavaCorePluginPreferencesNew().*/
/*!severity: info*/
org.eclipse.jdt.internal.ui.JavaPlugin.getJavaCorePluginPreferences()
=> org.eclipse.jdt.internal.ui.JavaPlugin.getJavaCorePluginPreferencesNew()
;;

/*!id: jdt.internal.text.javacodereader.singlecharreader-to-singlecharacterreader*/
/*!description: Replace internal SingleCharReader with SingleCharacterReader (type rename).*/
/*!severity: info*/
org.eclipse.jface.internal.text.html.SingleCharReader
=> org.eclipse.text.readers.SingleCharacterReader
;;

/*!id: jdt.internal.text.correction.proposals.fixcorrectionproposal.getimagedata.addzoom*/
/*!description: Add zoom argument to Image.getImageData() call in FixCorrectionProposal for high-res images.*/
/*!severity: info*/
$image.getImageData().width
=> $image.getImageData(100).width
;;

/*!id: jdt.internal.text.java.hover.sourceviewerinformationcontrol.getaveragecharwidth.rename*/
/*!description: Rename getAverageCharWidth() to getAverageCharacterWidth() for improved precision.*/
/*!severity: info*/
$gc.getFontMetrics().getAverageCharWidth()
=> $gc.getFontMetrics().getAverageCharacterWidth()
;;

/*!id: jdt.internal.text.java.hover.sourceviewerinformationcontrol.computeconstraints.addcast*/
/*!description: Add explicit (int) cast for width calculation in SourceViewerInformationControl to handle double precision.*/
/*!severity: info*/
$widthInChars * $width
:: inClass("org.eclipse.jdt.internal.ui.text.java.hover.SourceViewerInformationControl") && inMethod("computeSizeConstraints") && instanceof($width, "double")
=> (int) ($widthInChars * $width)
;;

/*!id: jdt.internal.ui.viewsupport.filteredelementtreeselectiondialog.super.addarg*/
/*!description: Add 'true' argument to FilteredTree super constructor for deep filtering in FilteredElementTreeSelectionDialog.*/
/*!severity: info*/
super($parent, $treeStyle, $patternFilter, true)
:: inClass("org.eclipse.jdt.internal.ui.viewsupport.FilteredElementTreeSelectionDialog")
=> super($parent, $treeStyle, $patternFilter, true, true)
;;

/*!id: jface.listselectiondialog.to.fluentbuilder*/
/*!description: Modernize ListSelectionDialog instantiation to use the fluent builder pattern.*/
/*!severity: info*/
new org.eclipse.jface.dialogs.ListSelectionDialog($shell, $input, $contentProvider, $labelProvider, $message)
=> org.eclipse.jface.dialogs.ListSelectionDialog.of($input).contentProvider($contentProvider).labelProvider($labelProvider).message($message).create($shell)
;;

/*!id: jdt.internal.javaeditor.completion.async.viewer-pattern-variable*/
/*!description: Modernize instanceof checks to use Java 16 pattern variables for clearer viewer access.*/
/*!severity: info*/
!(org.eclipse.jdt.ui.text.java.JavaSourceViewer) $context.getViewer()).isAsyncCompletionActive()
:: sourceVersionGE(16)
=> !(($context.getViewer()) instanceof org.eclipse.jdt.ui.javaeditor.JavaSourceViewer viewer) || !viewer.isAsyncCompletionActive()
;;

dslRuleAfterChange:
/*!id: jdt.internal.javaeditor.completion.async.viewer-pattern-variable*/
/*!description: Modernize instanceof checks to use Java 16 pattern variables for clearer viewer access.*/
/*!severity: info*/
!( $contextViewer instanceof org.eclipse.jdt.ui.javaeditor.JavaSourceViewer) || !((org.eclipse.jdt.ui.javaeditor.JavaSourceViewer) $contextViewer).isAsyncCompletionActive()
:: $contextViewer instanceof org.eclipse.jdt.ui.javaeditor.JavaSourceViewer && sourceVersionGE(16)
=> !( $contextViewer instanceof org.eclipse.jdt.ui.javaeditor.JavaSourceViewer viewer) || !viewer.isAsyncCompletionActive()
;;

Assert.isLegal($cond)
=>
if (!($cond)) {
    throw new java.lang.IllegalArgumentException(java.util.Arrays.stream(allWorkingSets).map(org.eclipse.jface.bindings.workingsets.IWorkingSet::getName).sorted().collect(java.util.stream.Collectors.toList()) + " does not contain all " + java.util.Arrays.stream(activeWorkingSets).map(org.eclipse.jface.bindings.workingsets.IWorkingSet::getName).sorted().collect(java.util.stream.Collectors.toList()));
}
;;

// Note: This is an illustrative DSL rule. The actual transformation for the second Assert.isLegal involves a different error message and condition.

/*!id: jdt.internal.workingsets.setactiveworkingsets.fix-illegalargumentexception*/
/*!description: Fixes IllegalArgumentException in WorkingSetModel by backing up fAllWorkingSets around getAllWorkingSets() call.*/
/*!severity: error*/
@aroundStatement: Assert.isLegal($assertionCall$)
List<org.eclipse.jface.bindings.workingsets.IWorkingSet> backup = this.fAllWorkingSets;
$matchedStatement$;
this.fAllWorkingSets = backup;
;;
